import type { Metadata } from 'next';
import Link from 'next/link';

type PageProps = {
  params: Promise<{ slug: string }>
};

export async function generateMetadata(
  { params }: PageProps
): Promise<Metadata> {
  const { slug } = await params;

  return {
    title: `Article: ${slug}`,
    description: `Deep dive for ${slug}`
  };
}

export default async function Page({ params }: PageProps) {
  const { slug } = await params;

  return (
    <>
      <h1>{slug}</h1>
      <Link href='/docs'>Back to docs</Link>
    </>
  );
}

type PageProps = {
  params: Promise<{ accountId: string }>
};

async function getAccount(accountId: string) {
  return db.account.findUnique({ where: { id: accountId } });
}

async function getInvoices(accountId: string) {
  return db.invoice.findMany({ where: { accountId } });
}

export default async function Page({ params }: PageProps) {
  const { accountId } = await params;

  const accountPromise = getAccount(accountId);
  const invoicesPromise = getInvoices(accountId);

  const [account, invoices] = await Promise.all([
    accountPromise,
    invoicesPromise
  ]);

  return <Dashboard account={account} invoices={invoices} />;
}

import { cacheLife, cacheTag } from 'next/cache';

export async function getProducts(category: string) {
  'use cache';

  cacheLife('hours');
  cacheTag(`products:${category}`);

  return db.product.findMany({
    where: { category },
    orderBy: { updatedAt: 'desc' }
  });
}

import { Suspense } from 'react';
import { cacheLife } from 'next/cache';
import { cookies } from 'next/headers';

async function ProductCatalog() {
  'use cache';
  cacheLife('hours');

  const products = await db.product.findMany();
  return <CatalogList products={products} />;
}

async function PersonalizedCart() {
  const cookieStore = await cookies();
  const cartId = cookieStore.get('cart')?.value;
  const cart = cartId ? await getCart(cartId) : null;
  return <CartPanel cart={cart} />;
}

export default function Page() {
  return (
    <>
      <ProductCatalog />
      <Suspense fallback={<CartSkeleton />}>
        <PersonalizedCart />
      </Suspense>
    </>
  );
}

'use server';

import { z } from 'zod';
import { updateTag } from 'next/cache';
import { redirect } from 'next/navigation';

const postSchema = z.object({
  title: z.string().min(3),
  body: z.string().min(20)
});

export async function createPost(formData: FormData) {
  const parsed = postSchema.safeParse({
    title: formData.get('title'),
    body: formData.get('body')
  });

  if (!parsed.success) {
    return { errors: parsed.error.flatten().fieldErrors };
  }

  const post = await db.post.create({ data: parsed.data });

  updateTag('posts');
  updateTag(`post:${post.id}`);

  redirect(`/posts/${post.id}`);
}
